import{_ as e,o as s,c as t,ag as n}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"RawBuf — Zero-Cost Byte-Level Memory Accessor","description":"","frontmatter":{},"headers":[],"relativePath":"guide/memory/rawbuf.md","filePath":"guide/memory/rawbuf.md"}'),l={name:"guide/memory/rawbuf.md"};function o(p,a,i,d,r,c){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="rawbuf-—-zero-cost-byte-level-memory-accessor" tabindex="-1">RawBuf — Zero-Cost Byte-Level Memory Accessor <a class="header-anchor" href="#rawbuf-—-zero-cost-byte-level-memory-accessor" aria-label="Permalink to &quot;RawBuf — Zero-Cost Byte-Level Memory Accessor&quot;">​</a></h1><p><code>RawBuf</code> is Vex&#39;s internal abstraction for byte-level memory access. It wraps an untyped <code>ptr</code> with typed load/store operations, replacing the raw C-style <code>(ptr as i64 + offset) as ptr</code> + <code>$load&lt;T&gt;</code> pattern.</p><div class="tip custom-block"><p class="custom-block-title">Prelude Type</p><p><code>RawBuf</code> is a <strong>prelude type</strong> — available in all Vex programs without any <code>import</code>. It is primarily used by the standard library internals (<code>String</code>, <code>str</code>, <code>Map</code>, <code>Vec</code>) but is also available for advanced use cases like custom allocators, binary parsers, and FFI buffer manipulation.</p></div><div class="info custom-block"><p class="custom-block-title">Zero Cost</p><p>All <code>RawBuf</code> methods are trivially inlined by LLVM. The generated machine code is <strong>bit-for-bit identical</strong> to manual pointer arithmetic + <code>$load/$store</code> intrinsics. There is no runtime overhead.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main() {</span></span>
<span class="line"><span>    // Allocate a raw buffer</span></span>
<span class="line"><span>    let mem = alloc(32);</span></span>
<span class="line"><span>    let! buf = RawBuf.of(mem);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Write a header: 4-byte magic + 4-byte version</span></span>
<span class="line"><span>    buf.storeU32(0, 0x56455821);   // &quot;VEX!&quot; magic</span></span>
<span class="line"><span>    buf.storeU32(4, 1);             // version 1</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Write payload at offset 8</span></span>
<span class="line"><span>    buf.storeU8(8, 72);            // &#39;H&#39;</span></span>
<span class="line"><span>    buf.storeU8(9, 105);           // &#39;i&#39;</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Read back</span></span>
<span class="line"><span>    let magic = buf.load&lt;u32&gt;(0);</span></span>
<span class="line"><span>    let version = buf.load&lt;u32&gt;(4);</span></span>
<span class="line"><span>    let ch = buf.load&lt;u8&gt;(8);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    $println(&quot;magic: 0x{:X}, v{}, first byte: {}&quot;, magic, version, ch);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    free(mem, 32);</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Compare with the old C-style approach:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Old way — unsafe, casts everywhere, easy to get wrong</span></span>
<span class="line"><span>unsafe {</span></span>
<span class="line"><span>    $store&lt;u32&gt;(mem, 0x56455821);</span></span>
<span class="line"><span>    $store&lt;u32&gt;((mem as i64 + 4) as ptr, 1);</span></span>
<span class="line"><span>    $store&lt;u8&gt;((mem as i64 + 8) as ptr, 72);</span></span>
<span class="line"><span>    let magic = $load&lt;u32&gt;(mem);</span></span>
<span class="line"><span>    let ch = $load&lt;u8&gt;((mem as i64 + 8) as ptr);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="struct-definition" tabindex="-1">Struct Definition <a class="header-anchor" href="#struct-definition" aria-label="Permalink to &quot;Struct Definition&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct RawBuf {</span></span>
<span class="line"><span>    public:</span></span>
<span class="line"><span>    base: ptr</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><code>RawBuf</code> is a single-field struct wrapping an untyped pointer. After inlining, it has exactly the same layout and performance as a bare <code>ptr</code>.</p><h2 id="creating-rawbuf" tabindex="-1">Creating RawBuf <a class="header-anchor" href="#creating-rawbuf" aria-label="Permalink to &quot;Creating RawBuf&quot;">​</a></h2><h3 id="from-existing-pointer" tabindex="-1">From Existing Pointer <a class="header-anchor" href="#from-existing-pointer" aria-label="Permalink to &quot;From Existing Pointer&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let mem = alloc(1024);</span></span>
<span class="line"><span>let buf = RawBuf.of(mem);</span></span></code></pre></div><h3 id="null-buffer" tabindex="-1">Null Buffer <a class="header-anchor" href="#null-buffer" aria-label="Permalink to &quot;Null Buffer&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let null_buf = RawBuf.null();</span></span>
<span class="line"><span>null_buf.isNull();  // true</span></span></code></pre></div><h3 id="from-struct-fields" tabindex="-1">From Struct Fields <a class="header-anchor" href="#from-struct-fields" aria-label="Permalink to &quot;From Struct Fields&quot;">​</a></h3><p>A common pattern in Vex internals — wrap a struct&#39;s data pointer:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Inside String implementation</span></span>
<span class="line"><span>let header = RawBuf.of((self.data_or_ptr as i64 - 8) as ptr);</span></span>
<span class="line"><span>let capacity = header.load&lt;u32&gt;(0);</span></span></code></pre></div><h2 id="pointer-arithmetic" tabindex="-1">Pointer Arithmetic <a class="header-anchor" href="#pointer-arithmetic" aria-label="Permalink to &quot;Pointer Arithmetic&quot;">​</a></h2><p>All offsets are in <strong>bytes</strong> (not elements). Arithmetic returns new <code>RawBuf</code> values — no mutation.</p><h3 id="at-offset-—-raw-pointer-at-offset" tabindex="-1">at(offset) — Raw Pointer at Offset <a class="header-anchor" href="#at-offset-—-raw-pointer-at-offset" aria-label="Permalink to &quot;at(offset) — Raw Pointer at Offset&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let buf = RawBuf.of(mem);</span></span>
<span class="line"><span>let p: ptr = buf.at(16);   // raw pointer to base + 16 bytes</span></span></code></pre></div><h3 id="advance-n-—-new-rawbuf-at-offset" tabindex="-1">advance(n) — New RawBuf at Offset <a class="header-anchor" href="#advance-n-—-new-rawbuf-at-offset" aria-label="Permalink to &quot;advance(n) — New RawBuf at Offset&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let buf = RawBuf.of(mem);</span></span>
<span class="line"><span>let payload = buf.advance(8);   // new RawBuf pointing to base + 8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Chainable</span></span>
<span class="line"><span>let deep = buf.advance(8).advance(4);  // base + 12</span></span></code></pre></div><h3 id="addr-—-integer-address" tabindex="-1">addr() — Integer Address <a class="header-anchor" href="#addr-—-integer-address" aria-label="Permalink to &quot;addr() — Integer Address&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let buf = RawBuf.of(mem);</span></span>
<span class="line"><span>let address: i64 = buf.addr();</span></span></code></pre></div><h3 id="isnull-—-null-check" tabindex="-1">isNull() — Null Check <a class="header-anchor" href="#isnull-—-null-check" aria-label="Permalink to &quot;isNull() — Null Check&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let buf = RawBuf.of(mem);</span></span>
<span class="line"><span>if !buf.isNull() {</span></span>
<span class="line"><span>    // safe to use</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="typed-loads-read" tabindex="-1">Typed Loads (Read) <a class="header-anchor" href="#typed-loads-read" aria-label="Permalink to &quot;Typed Loads (Read)&quot;">​</a></h2><p>All load methods take a <strong>byte offset</strong> from the base pointer.</p><h3 id="fixed-width-loads" tabindex="-1">Fixed-Width Loads <a class="header-anchor" href="#fixed-width-loads" aria-label="Permalink to &quot;Fixed-Width Loads&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let buf = RawBuf.of(mem);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let byte_val:  u8  = buf.load&lt;u8&gt;(0);     // 1 byte</span></span>
<span class="line"><span>let word_val:  u32 = buf.load&lt;u32&gt;(4);     // 4 bytes</span></span>
<span class="line"><span>let dword_val: u64 = buf.load&lt;u64&gt;(8);     // 8 bytes</span></span>
<span class="line"><span>let signed32:  i32 = buf.load&lt;i32&gt;(16);    // 4 bytes (signed)</span></span>
<span class="line"><span>let signed64:  i64 = buf.load&lt;i64&gt;(24);    // 8 bytes (signed)</span></span></code></pre></div><h3 id="generic-load" tabindex="-1">Generic Load <a class="header-anchor" href="#generic-load" aria-label="Permalink to &quot;Generic Load&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Load any type T at byte offset</span></span>
<span class="line"><span>let val: MyStruct = buf.load&lt;MyStruct&gt;(0);</span></span></code></pre></div><h3 id="indexed-load-array-access" tabindex="-1">Indexed Load (Array Access) <a class="header-anchor" href="#indexed-load-array-access" aria-label="Permalink to &quot;Indexed Load (Array Access)&quot;">​</a></h3><p>Load the n-th element of type <code>T</code>, automatically computing <code>offset = idx * sizeof(T)</code>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Array of i64 at base pointer</span></span>
<span class="line"><span>let first:  i64 = buf.loadAt&lt;i64&gt;(0);    // offset 0</span></span>
<span class="line"><span>let second: i64 = buf.loadAt&lt;i64&gt;(1);    // offset 8</span></span>
<span class="line"><span>let third:  i64 = buf.loadAt&lt;i64&gt;(2);    // offset 16</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Array of u32</span></span>
<span class="line"><span>let item: u32 = buf.loadAt&lt;u32&gt;(5);      // offset 20</span></span></code></pre></div><p>This is the primary API used by <code>Map&lt;K, V&gt;</code> for its key/value slot arrays.</p><h2 id="typed-stores-write" tabindex="-1">Typed Stores (Write) <a class="header-anchor" href="#typed-stores-write" aria-label="Permalink to &quot;Typed Stores (Write)&quot;">​</a></h2><p>All store methods take a <strong>byte offset</strong> and a value.</p><h3 id="fixed-width-stores" tabindex="-1">Fixed-Width Stores <a class="header-anchor" href="#fixed-width-stores" aria-label="Permalink to &quot;Fixed-Width Stores&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! buf = RawBuf.of(mem);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>buf.storeU8(0, 0xFF);             // 1 byte</span></span>
<span class="line"><span>buf.storeU32(4, 42);              // 4 bytes</span></span>
<span class="line"><span>buf.store&lt;u64&gt;(8, 0xDEADBEEF);     // 8 bytes</span></span>
<span class="line"><span>buf.store&lt;i32&gt;(16, -1);             // 4 bytes (signed)</span></span>
<span class="line"><span>buf.store&lt;i64&gt;(24, -9999);          // 8 bytes (signed)</span></span></code></pre></div><h3 id="generic-store" tabindex="-1">Generic Store <a class="header-anchor" href="#generic-store" aria-label="Permalink to &quot;Generic Store&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>buf.store&lt;MyStruct&gt;(0, my_value);</span></span></code></pre></div><h3 id="indexed-store-array-access" tabindex="-1">Indexed Store (Array Access) <a class="header-anchor" href="#indexed-store-array-access" aria-label="Permalink to &quot;Indexed Store (Array Access)&quot;">​</a></h3><p>Store at the n-th element slot of type <code>T</code>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>buf.storeAt&lt;i64&gt;(0, 100);    // offset 0</span></span>
<span class="line"><span>buf.storeAt&lt;i64&gt;(1, 200);    // offset 8</span></span>
<span class="line"><span>buf.storeAt&lt;i64&gt;(2, 300);    // offset 16</span></span></code></pre></div><h2 id="bulk-memory-operations" tabindex="-1">Bulk Memory Operations <a class="header-anchor" href="#bulk-memory-operations" aria-label="Permalink to &quot;Bulk Memory Operations&quot;">​</a></h2><h3 id="copyfrom-—-read-into-buffer" tabindex="-1">copyFrom — Read Into Buffer <a class="header-anchor" href="#copyfrom-—-read-into-buffer" aria-label="Permalink to &quot;copyFrom — Read Into Buffer&quot;">​</a></h3><p>Copy <code>len</code> bytes from an external pointer into this buffer:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! buf = RawBuf.of(dest);</span></span>
<span class="line"><span>buf.copyFrom(source_ptr, 64);   // copy 64 bytes: source → buf</span></span></code></pre></div><h3 id="copyto-—-write-from-buffer" tabindex="-1">copyTo — Write From Buffer <a class="header-anchor" href="#copyto-—-write-from-buffer" aria-label="Permalink to &quot;copyTo — Write From Buffer&quot;">​</a></h3><p>Copy <code>len</code> bytes from this buffer to an external destination:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let buf = RawBuf.of(source);</span></span>
<span class="line"><span>buf.copyTo(dest_ptr, 64);      // copy 64 bytes: buf → dest</span></span></code></pre></div><h3 id="cmp-—-compare-memory" tabindex="-1">cmp — Compare Memory <a class="header-anchor" href="#cmp-—-compare-memory" aria-label="Permalink to &quot;cmp — Compare Memory&quot;">​</a></h3><p>Compare <code>len</code> bytes with another pointer (like <code>memcmp</code>):</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let buf = RawBuf.of(mem1);</span></span>
<span class="line"><span>let result = buf.cmp(mem2, 32);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if result == 0 {</span></span>
<span class="line"><span>    $println(&quot;equal&quot;);</span></span>
<span class="line"><span>} else if result &lt; 0 {</span></span>
<span class="line"><span>    $println(&quot;buf &lt; other&quot;);</span></span>
<span class="line"><span>} else {</span></span>
<span class="line"><span>    $println(&quot;buf &gt; other&quot;);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="fill-—-fill-memory" tabindex="-1">fill — Fill Memory <a class="header-anchor" href="#fill-—-fill-memory" aria-label="Permalink to &quot;fill — Fill Memory&quot;">​</a></h3><p>Fill <code>len</code> bytes with a value (like <code>memset</code>):</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! buf = RawBuf.of(mem);</span></span>
<span class="line"><span>buf.fill(0, 1024);     // zero-initialize 1024 bytes</span></span>
<span class="line"><span>buf.fill(0xFF, 64);    // fill with 0xFF</span></span></code></pre></div><h2 id="real-world-usage-patterns" tabindex="-1">Real-World Usage Patterns <a class="header-anchor" href="#real-world-usage-patterns" aria-label="Permalink to &quot;Real-World Usage Patterns&quot;">​</a></h2><h3 id="binary-header-parsing" tabindex="-1">Binary Header Parsing <a class="header-anchor" href="#binary-header-parsing" aria-label="Permalink to &quot;Binary Header Parsing&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn parse_header(data: ptr): FileHeader {</span></span>
<span class="line"><span>    let buf = RawBuf.of(data);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    let magic   = buf.load&lt;u32&gt;(0);</span></span>
<span class="line"><span>    let version = buf.load&lt;u32&gt;(4);</span></span>
<span class="line"><span>    let flags   = buf.load&lt;u64&gt;(8);</span></span>
<span class="line"><span>    let count   = buf.load&lt;u32&gt;(16);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    return FileHeader { magic, version, flags, count };</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="hash-map-slot-access" tabindex="-1">Hash Map Slot Access <a class="header-anchor" href="#hash-map-slot-access" aria-label="Permalink to &quot;Hash Map Slot Access&quot;">​</a></h3><p>This is how Vex&#39;s <code>Map&lt;K, V&gt;</code> uses <code>RawBuf</code> internally:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Inside Map implementation</span></span>
<span class="line"><span>let keys = RawBuf.of(self.key_data);</span></span>
<span class="line"><span>let vals = RawBuf.of(self.val_data);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Read key/value at slot index</span></span>
<span class="line"><span>let k: K = keys.loadAt&lt;K&gt;(slot);</span></span>
<span class="line"><span>let v: V = vals.loadAt&lt;V&gt;(slot);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Write key/value at slot index</span></span>
<span class="line"><span>keys.storeAt&lt;K&gt;(slot, new_key);</span></span>
<span class="line"><span>vals.storeAt&lt;V&gt;(slot, new_value);</span></span></code></pre></div><h3 id="string-concatenation-buffer" tabindex="-1">String Concatenation Buffer <a class="header-anchor" href="#string-concatenation-buffer" aria-label="Permalink to &quot;String Concatenation Buffer&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn concat(a: ptr, a_len: i64, b: ptr, b_len: i64): ptr {</span></span>
<span class="line"><span>    let total = a_len + b_len + 1;</span></span>
<span class="line"><span>    let mem = alloc(total);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    let! buf = RawBuf.of(mem);</span></span>
<span class="line"><span>    buf.copyFrom(a, a_len);                    // copy first string</span></span>
<span class="line"><span>    buf.advance(a_len).copyFrom(b, b_len);     // copy second string</span></span>
<span class="line"><span>    buf.storeU8(a_len + b_len, 0);             // null terminator</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    return mem;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="custom-allocator-metadata" tabindex="-1">Custom Allocator Metadata <a class="header-anchor" href="#custom-allocator-metadata" aria-label="Permalink to &quot;Custom Allocator Metadata&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn alloc_with_header(size: i64): ptr {</span></span>
<span class="line"><span>    let total = 16 + size;   // 16-byte header</span></span>
<span class="line"><span>    let mem = alloc(total);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    let! hdr = RawBuf.of(mem);</span></span>
<span class="line"><span>    hdr.store&lt;u64&gt;(0, size as u64);     // block size</span></span>
<span class="line"><span>    hdr.store&lt;u64&gt;(8, 0);               // flags / ref count</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Return pointer past the header</span></span>
<span class="line"><span>    return hdr.at(16);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn get_block_size(payload: ptr): u64 {</span></span>
<span class="line"><span>    let hdr = RawBuf.of((payload as i64 - 16) as ptr);</span></span>
<span class="line"><span>    return hdr.load&lt;u64&gt;(0);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="rawbuf-vs-ptr-t-vs-span-t" tabindex="-1">RawBuf vs Ptr&lt;T&gt; vs Span&lt;T&gt; <a class="header-anchor" href="#rawbuf-vs-ptr-t-vs-span-t" aria-label="Permalink to &quot;RawBuf vs Ptr\\&lt;T\\&gt; vs Span\\&lt;T\\&gt;&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th><code>RawBuf</code></th><th><code>Ptr&lt;T&gt;</code></th><th><code>Span&lt;T&gt;</code></th></tr></thead><tbody><tr><td><strong>Typed</strong></td><td>Untyped (byte offsets)</td><td>Typed (element offsets)</td><td>Typed (element offsets)</td></tr><tr><td><strong>Bounds checking</strong></td><td>None</td><td>None</td><td>Yes</td></tr><tr><td><strong>Owns memory</strong></td><td>No</td><td>No</td><td>No</td></tr><tr><td><strong>Best for</strong></td><td>Binary layout, mixed types</td><td>Typed arrays, FFI</td><td>Safe iteration, slicing</td></tr><tr><td><strong>Stride</strong></td><td>Manual (byte offsets)</td><td>Automatic (element size)</td><td>Automatic (element size)</td></tr><tr><td><strong>Generic load/store</strong></td><td><code>loadAt&lt;T&gt;</code> / <code>storeAt&lt;T&gt;</code></td><td><code>readAt</code> / <code>writeAt</code></td><td><code>get</code> / —</td></tr></tbody></table><p><strong>Rule of thumb:</strong></p><ul><li>Use <code>Ptr&lt;T&gt;</code> for homogeneous typed arrays</li><li>Use <code>Span&lt;T&gt;</code> for bounds-checked views over typed data</li><li>Use <code>RawBuf</code> for binary protocols, mixed-type layouts, and internal stdlib plumbing</li></ul><h2 id="method-reference" tabindex="-1">Method Reference <a class="header-anchor" href="#method-reference" aria-label="Permalink to &quot;Method Reference&quot;">​</a></h2><h3 id="constructors" tabindex="-1">Constructors <a class="header-anchor" href="#constructors" aria-label="Permalink to &quot;Constructors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>RawBuf.of(p)</code></td><td>Wrap raw pointer</td></tr><tr><td><code>RawBuf.null()</code></td><td>Null buffer</td></tr></tbody></table><h3 id="pointer-arithmetic-1" tabindex="-1">Pointer Arithmetic <a class="header-anchor" href="#pointer-arithmetic-1" aria-label="Permalink to &quot;Pointer Arithmetic&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>.at(offset)</code></td><td>Raw pointer at byte offset</td></tr><tr><td><code>.advance(n)</code></td><td>New RawBuf offset by n bytes</td></tr><tr><td><code>.addr()</code></td><td>Base address as <code>i64</code></td></tr><tr><td><code>.isNull()</code></td><td>Check if base is null</td></tr></tbody></table><h3 id="typed-loads" tabindex="-1">Typed Loads <a class="header-anchor" href="#typed-loads" aria-label="Permalink to &quot;Typed Loads&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>.load&lt;u8&gt;(off)</code></td><td>Load <code>u8</code> at byte offset</td></tr><tr><td><code>.load&lt;u32&gt;(off)</code></td><td>Load <code>u32</code> at byte offset</td></tr><tr><td><code>.load&lt;u64&gt;(off)</code></td><td>Load <code>u64</code> at byte offset</td></tr><tr><td><code>.load&lt;i32&gt;(off)</code></td><td>Load <code>i32</code> at byte offset</td></tr><tr><td><code>.load&lt;i64&gt;(off)</code></td><td>Load <code>i64</code> at byte offset</td></tr><tr><td><code>.load&lt;T&gt;(off)</code></td><td>Load any type <code>T</code> at byte offset</td></tr><tr><td><code>.loadAt&lt;T&gt;(idx)</code></td><td>Load <code>T</code> at index (stride = <code>sizeof(T)</code>)</td></tr></tbody></table><h3 id="typed-stores" tabindex="-1">Typed Stores <a class="header-anchor" href="#typed-stores" aria-label="Permalink to &quot;Typed Stores&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>.storeU8(off, val)</code></td><td>Store <code>u8</code> at byte offset</td></tr><tr><td><code>.storeU32(off, val)</code></td><td>Store <code>u32</code> at byte offset</td></tr><tr><td><code>.store&lt;u64&gt;(off, val)</code></td><td>Store <code>u64</code> at byte offset</td></tr><tr><td><code>.store&lt;i32&gt;(off, val)</code></td><td>Store <code>i32</code> at byte offset</td></tr><tr><td><code>.store&lt;i64&gt;(off, val)</code></td><td>Store <code>i64</code> at byte offset</td></tr><tr><td><code>.store&lt;T&gt;(off, val)</code></td><td>Store any type <code>T</code> at byte offset</td></tr><tr><td><code>.storeAt&lt;T&gt;(idx, val)</code></td><td>Store <code>T</code> at index (stride = <code>sizeof(T)</code>)</td></tr></tbody></table><h3 id="bulk-operations" tabindex="-1">Bulk Operations <a class="header-anchor" href="#bulk-operations" aria-label="Permalink to &quot;Bulk Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>.copyFrom(src, len)</code></td><td>Copy <code>len</code> bytes from <code>src</code> into buffer</td></tr><tr><td><code>.copyTo(dst, len)</code></td><td>Copy <code>len</code> bytes from buffer to <code>dst</code></td></tr><tr><td><code>.cmp(other, len)</code></td><td>Compare <code>len</code> bytes (memcmp semantics)</td></tr><tr><td><code>.fill(val, len)</code></td><td>Fill <code>len</code> bytes with <code>val</code> (memset semantics)</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./ptr-t">Ptr&lt;T&gt;</a> — Typed generic pointer with element-level operations</li><li><a href="./span-t">Span&lt;T&gt;</a> — Bounds-checked fat pointer for safe iteration</li><li><a href="./ownership">Ownership</a> — Vex&#39;s ownership model</li><li><a href="./safety">Safety</a> — When and how to use unsafe code</li></ul>`,88)])])}const f=e(l,[["render",o]]);export{h as __pageData,f as default};
